    def to_dict(self) -> Dict[str, Any]:
        with self._lock:
            return {
                "plan_id": self.plan_id,
                "state": self.state.value,
                "attempts": self.attempts,
                "max_retries": self.max_retries,
                "history": [tr.to_dict() for tr in self.history],
            }

    @staticmethod
    def from_dict(d: Dict[str, Any], persistence_callback: Optional[Callable[[str, Dict[str, Any]], None]] = None) -> "StateMachine":
        sm = StateMachine(max_retries=d.get("max_retries", 3), persistence_callback=persistence_callback)
        sm.plan_id = d.get("plan_id")
        sm.state = State(d["state"])
        sm.attempts = int(d.get("attempts", 0))
        sm.history = [TransitionRecord.from_dict(h) for h in d.get("history", [])]
        return sm

    def current_state(self) -> State:
        with self._lock:
            return self.state

    def clear_history(self) -> None:
        with self._lock:
            self.history = []

    def __repr__(self) -> str:
        return f"<StateMachine state={self.state} attempts={self.attempts} history_len={len(self.history)}>"

import os
from dotenv import load_dotenv

# This tells Python to look for your local .env file
load_dotenv()

class LLMService:
    def __init__(self):
        # These variables pull from your local .env
        self.api_key = os.getenv("LLM_API_KEY")
        self.endpoint = os.getenv("LLM_ENDPOINT")

    def call_llm(self, prompt: str, system_prompt: str = "You are a helpful coding assistant."):
        if not self.api_key or not self.endpoint:
            raise ValueError("API Key or Endpoint missing from your local .env file!")

        import requests

        headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json"
        }

        payload = {
            "model": "codestral-latest",
            "messages": [
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": prompt}
            ]
        }

        response = requests.post(self.endpoint, headers=headers, json=payload)
        response.raise_for_status()
        return response.json()["choices"][0]["message"]["content"]

# simple scheduler for local MCP (async, no external dependency)
import asyncio
from typing import Callable, Dict
from datetime import datetime, timedelta

class SimpleScheduler:
    def __init__(self):
        self._jobs = {}  # job_id -> (next_run, coro_fn, interval_seconds)

    def schedule_every(self, job_id: str, coro_fn: Callable[[], None], interval_seconds: int):
        next_run = datetime.utcnow() + timedelta(seconds=interval_seconds)
        self._jobs[job_id] = {"next_run": next_run, "fn": coro_fn, "interval": interval_seconds}

    async def run_forever(self):
        while True:
            now = datetime.utcnow()
            for job_id, meta in list(self._jobs.items()):
                if meta["next_run"] <= now:
                    # dispatch without awaiting to avoid blocking
                    asyncio.create_task(meta["fn"]())
                    meta["next_run"] = now + timedelta(seconds=meta["interval"])
            await asyncio.sleep(1)

