        };

        // Three.js setup
        const canvas = document.getElementById('canvas');
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87ceeb);

        // Camera
        const camera = new THREE.OrthographicCamera(
            -400, 400, 300, -300, 1, 5000
        );
        camera.position.set(0, 150, 150);
        camera.lookAt(0, 0, 0);

        // Renderer
        const renderer = new THREE.WebGLRenderer({ 
            canvas: canvas, 
            antialias: true,
            alpha: true
        });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;

        // Lights
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const directionalLight = new THREE.DirectionalLight(0xffffff, 0.8);
        directionalLight.position.set(100, 100, 100);
        directionalLight.castShadow = true;
        scene.add(directionalLight);

        // Create Base44 world grid
        function createBase44World() {
            const CELL_SIZE = 100;
            const LAYER_HEIGHT = 50;

            // Ground layer (blue-green)
            for (let x = 0; x < 4; x++) {
                for (let y = 0; y < 4; y++) {
                    createZoneMesh(x, y, 0, 0x4488ff);
                }
            }

            // Elevated layer (yellow-orange)
            for (let x = 0; x < 4; x++) {
                for (let y = 0; y < 4; y++) {
                    createZoneMesh(x, y, 1, 0xffaa44);
                }
            }

            // Aerial layer (red-pink)
            for (let x = 0; x < 4; x++) {
                for (let y = 0; y < 3; y++) {
                    createZoneMesh(x, y, 2, 0xff6688);
                }
            }

            function createZoneMesh(gridX, gridY, layer, color) {
                const CELL_SIZE = 100;
                const LAYER_HEIGHT = 50;

                const geometry = new THREE.BoxGeometry(CELL_SIZE, 5, CELL_SIZE);
                const material = new THREE.MeshLambertMaterial({ color: color });
                const mesh = new THREE.Mesh(geometry, material);

                mesh.position.set(
                    gridX * CELL_SIZE + CELL_SIZE / 2,
                    layer * LAYER_HEIGHT,
                    gridY * CELL_SIZE + CELL_SIZE / 2
                );
                mesh.castShadow = true;
                mesh.receiveShadow = true;

                scene.add(mesh);
            }
        }

        // Create avatar spheres
        function createAvatars() {
            const avatarData = [
                { name: 'Manager', color: 0x0066cc, x: -150 },
                { name: 'Conductor', color: 0x0066cc, x: -50 },
                { name: 'Architect', color: 0xff6600, x: 50 },
                { name: 'Coder', color: 0x0066cc, x: 150 },
                { name: 'Tester', color: 0x0066cc, x: -150 },
                { name: 'Researcher', color: 0xff6600, x: -50 },
                { name: 'Physicist', color: 0x0066cc, x: 50 },
            ];

            avatarData.forEach((avatar, idx) => {
                const geometry = new THREE.SphereGeometry(8, 32, 32);
                const material = new THREE.MeshStandardMaterial({ color: avatar.color });
                const mesh = new THREE.Mesh(geometry, material);

                mesh.position.set(avatar.x, 100, 100 + idx * 30);
                mesh.castShadow = true;
                mesh.receiveShadow = true;
                mesh.userData = { type: 'avatar', name: avatar.name };

                scene.add(mesh);
            });
        }

        // Update UI
        function updateUI(state) {
            document.getElementById('frame').textContent = state.frame;
            document.getElementById('preset').textContent = state.preset;
            document.getElementById('objects').textContent = (scene.children.length - 2); // Exclude lights

            // Update avatar panels
            const panelsContainer = document.getElementById('avatar-panels');
            const avatarNames = ['Manager', 'Conductor', 'Architect', 'Coder', 'Tester', 'Researcher', 'Physicist'];
            const avatarStyles = ['engineer', 'engineer', 'designer', 'engineer', 'engineer', 'designer', 'engineer'];

            if (panelsContainer.children.length === 0) {
                avatarNames.forEach((name, idx) => {
                    const panel = document.createElement('div');
                    panel.className = `avatar-panel ${avatarStyles[idx]}`;
                    const score = 0.5 + Math.random() * 0.5; // Random score 0.5-1.0
                    panel.innerHTML = `
                        <h4>${name}</h4>
                        <div class="score-bar">
                            <div class="score-fill" style="width: ${score * 100}%; background: ${getScoreColor(score)}">${score.toFixed(2)}</div>
                        </div>
                    `;
                    panelsContainer.appendChild(panel);
                });
            }
        }

        function getScoreColor(score) {
            if (score >= 0.9) return '#00ff00';
            if (score >= 0.7) return '#ffff00';
            if (score >= 0.5) return '#ffaa00';
            return '#ff0000';
        }

        // Animation loop
        function animate() {
            requestAnimationFrame(animate);

            // Rotate avatars
            scene.getObjectsByProperty('userData', { type: 'avatar' }).forEach(obj => {
                obj.rotation.y += 0.005;
            });

            gameState.frame++;
            updateUI(gameState);

            renderer.render(scene, camera);
        }

        // Initialize
        createBase44World();
        createAvatars();
        updateUI(gameState);
        animate();

        // Handle window resize
        window.addEventListener('resize', () => {
            const width = window.innerWidth;
            const height = window.innerHeight;
            camera.left = -width / 5;
            camera.right = width / 5;
            camera.top = height / 5;
            camera.bottom = -height / 5;
            camera.updateProjectionMatrix();
            renderer.setSize(width, height);
        });

        // Keyboard input
        const keys = {};
        window.addEventListener('keydown', (e) => keys[e.key] = true);
        window.addEventListener('keyup', (e) => keys[e.key] = false);
    </script>
</body>
</html>
